import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';

const Register = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    confirmPassword: '',
    branch: 'CSE',
    semester: '1'
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false); // Changed to boolean
  const navigate = useNavigate();

  const branches = ['CSE', 'ECE', 'EEE', 'Mechanical', 'Civil', 'IT', 'Other'];
  const semesters = ['1', '2', '3', '4', '5', '6', '7', '8'];

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setSuccess(false);

    // Validation
    if (formData.password !== formData.confirmPassword) {
      setError('Passwords do not match');
      setLoading(false);
      return;
    }

    if (formData.password.length < 6) {
      setError('Password must be at least 6 characters');
      setLoading(false);
      return;
    }

    try {
      const response = await fetch('http://localhost:5000/api/auth/register', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          name: formData.name,
          email: formData.email,
          password: formData.password,
          branch: formData.branch,
          semester: parseInt(formData.semester)
        }),
      });

      const data = await response.json();

      if (response.ok) {
        setSuccess(true);
        
        // ✅ REGISTRATION SUCCESSFUL - DON'T AUTO LOGIN
        // Clear form
        setFormData({
          name: '',
          email: '',
          password: '',
          confirmPassword: '',
          branch: 'CSE',
          semester: '1'
        });
        
        // Show success message with login prompt
        setTimeout(() => {
          // Optionally redirect to login page
          // navigate('/login');
        }, 3000);
        
      } else {
        setError(data.error || 'Registration failed');
      }
    } catch (err) {
      setError('Network error. Check backend connection.');
    } finally {
      setLoading(false);
    }
  };

  const styles = {
    container: {
      maxWidth: '500px',
      margin: '0 auto',
      padding: '2rem 1rem',
      minHeight: '80vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center'
    },
    card: {
      width: '100%',
      background: 'white',
      padding: '2.5rem',
      borderRadius: '15px',
      boxShadow: '0 10px 25px rgba(0,0,0,0.1)'
    },
    title: {
      textAlign: 'center',
      marginBottom: '2rem',
      color: '#1f2937',
      fontSize: '2rem'
    },
    formGroup: {
      marginBottom: '1.5rem'
    },
    label: {
      display: 'block',
      marginBottom: '0.5rem',
      fontWeight: '500',
      color: '#374151'
    },
    input: {
      width: '100%',
      padding: '0.75rem',
      borderRadius: '8px',
      border: '1px solid #d1d5db',
      fontSize: '1rem',
      transition: 'border 0.3s',
      '&:focus': {
        borderColor: '#4f46e5',
        boxShadow: '0 0 0 3px rgba(79, 70, 229, 0.1)',
        outline: 'none'
      }
    },
    select: {
      width: '100%',
      padding: '0.75rem',
      borderRadius: '8px',
      border: '1px solid #d1d5db',
      fontSize: '1rem',
      background: 'white',
      '&:focus': {
        borderColor: '#4f46e5',
        outline: 'none'
      }
    },
    button: {
      width: '100%',
      padding: '0.875rem',
      background: '#4f46e5',
      color: 'white',
      border: 'none',
      borderRadius: '8px',
      fontSize: '1rem',
      fontWeight: '500',
      cursor: 'pointer',
      marginTop: '1rem',
      transition: 'all 0.3s',
      '&:hover': {
        background: '#4338ca',
        transform: 'translateY(-2px)'
      },
      '&:disabled': {
        background: '#9ca3af',
        cursor: 'not-allowed',
        transform: 'none'
      }
    },
    error: {
      background: '#fee2e2',
      color: '#dc2626',
      padding: '0.75rem',
      borderRadius: '8px',
      marginBottom: '1rem',
      textAlign: 'center'
    },
    successCard: {
      background: 'linear-gradient(135deg, #d1fae5 0%, #a7f3d0 100%)',
      padding: '2rem',
      borderRadius: '10px',
      textAlign: 'center',
      marginBottom: '2rem',
      border: '2px solid #10b981'
    },
    successIcon: {
      fontSize: '3rem',
      marginBottom: '1rem'
    },
    successTitle: {
      color: '#065f46',
      marginBottom: '0.5rem'
    },
    successText: {
      color: '#047857',
      marginBottom: '1.5rem'
    },
    loginLink: {
      textAlign: 'center',
      marginTop: '1.5rem',
      color: '#6b7280'
    },
    link: {
      color: '#4f46e5',
      textDecoration: 'none',
      fontWeight: '500',
      fontSize: '1.1rem'
    },
    loginButton: {
      display: 'inline-block',
      background: '#10b981',
      color: 'white',
      padding: '0.75rem 1.5rem',
      borderRadius: '8px',
      textDecoration: 'none',
      fontWeight: '500',
      marginTop: '1rem',
      transition: 'all 0.3s',
      '&:hover': {
        background: '#059669',
        transform: 'scale(1.05)'
      }
    }
  };

  // ✅ SUCCESS STATE - Show success message instead of form
  if (success) {
    return (
      <div style={styles.container}>
        <div style={styles.card}>
          <div style={styles.successCard}>
            <div style={styles.successIcon}>✅</div>
            <h2 style={styles.successTitle}>Registration Successful!</h2>
            <p style={styles.successText}>
              Your account has been created successfully.
              <br />
              <strong>Please login to continue.</strong>
            </p>
            <Link to="/login" style={styles.loginButton}>
              🔐 Go to Login Page
            </Link>
          </div>
          
          <div style={{ textAlign: 'center', marginTop: '2rem' }}>
            <p style={{ color: '#6b7280' }}>
              Want to create another account?
            </p>
            <button
              onClick={() => setSuccess(false)}
              style={{
                background: 'transparent',
                color: '#4f46e5',
                border: '1px solid #4f46e5',
                padding: '0.5rem 1rem',
                borderRadius: '8px',
                cursor: 'pointer',
                marginTop: '0.5rem'
              }}
            >
              Register Another Account
            </button>
          </div>
        </div>
      </div>
    );
  }

  // ✅ REGISTRATION FORM (normal state)
  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h2 style={styles.title}>📝 Create Account</h2>
        
        <div style={{
          background: '#f0f9ff',
          padding: '1rem',
          borderRadius: '8px',
          marginBottom: '1.5rem',
          borderLeft: '4px solid #0ea5e9'
        }}>
          <p style={{ margin: 0, color: '#0369a1', fontSize: '0.9rem' }}>
            <strong>Note:</strong> After registration, you need to login separately.
          </p>
        </div>
        
        {error && (
          <div style={styles.error}>❌ {error}</div>
        )}
        
        <form onSubmit={handleSubmit}>
          <div style={styles.formGroup}>
            <label style={styles.label}>Full Name *</label>
            <input
              type="text"
              name="name"
              value={formData.name}
              onChange={handleChange}
              required
              style={styles.input}
              placeholder="Enter your full name"
            />
          </div>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Email Address *</label>
            <input
              type="email"
              name="email"
              value={formData.email}
              onChange={handleChange}
              required
              style={styles.input}
              placeholder="student@example.com"
            />
          </div>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Branch *</label>
            <select
              name="branch"
              value={formData.branch}
              onChange={handleChange}
              style={styles.select}
              required
            >
              {branches.map(branch => (
                <option key={branch} value={branch}>{branch}</option>
              ))}
            </select>
          </div>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Semester *</label>
            <select
              name="semester"
              value={formData.semester}
              onChange={handleChange}
              style={styles.select}
              required
            >
              {semesters.map(sem => (
                <option key={sem} value={sem}>Semester {sem}</option>
              ))}
            </select>
          </div>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Password *</label>
            <input
              type="password"
              name="password"
              value={formData.password}
              onChange={handleChange}
              required
              style={styles.input}
              placeholder="At least 6 characters"
            />
          </div>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Confirm Password *</label>
            <input
              type="password"
              name="confirmPassword"
              value={formData.confirmPassword}
              onChange={handleChange}
              required
              style={styles.input}
              placeholder="Re-enter your password"
            />
          </div>
          
          <button
            type="submit"
            disabled={loading}
            style={{
              ...styles.button,
              background: loading ? '#9ca3af' : '#4f46e5'
            }}
          >
            {loading ? 'Creating Account...' : 'Create Account'}
          </button>
        </form>
        
        <div style={styles.loginLink}>
          <p>Already have an account? <Link to="/login" style={styles.link}>Login here</Link></p>
        </div>
        
        <div style={{
          marginTop: '2rem',
          padding: '1rem',
          background: '#f3f4f6',
          borderRadius: '8px',
          fontSize: '0.9rem',
          color: '#6b7280'
        }}>
          <p style={{ marginBottom: '0.5rem', fontWeight: '500' }}>📋 Registration Process:</p>
          <ol style={{ margin: 0, paddingLeft: '1.5rem' }}>
            <li>Fill registration form</li>
            <li>Verify your email (optional)</li>
            <li>Go to login page</li>
            <li>Login with your credentials</li>
            <li>Start uploading/downloading</li>
          </ol>
        </div>
      </div>
    </div>
  );
};

export default Register;
